var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Krgh...!","TWN":"呃……!"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네를 습격했던 수많은 침식체들을 기억하나?","JPN":"君を襲った多くの侵食体を覚えているかね？","ENG":"Do you remember all the C.O.s that attacked you?","TWN":"還記得襲擊你的那些侵蝕體嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"바로 변이조차 하지 못하고 도태된 자들의 말로지.","JPN":"変異すらできず淘汰された者たちの成れの果てだ。","ENG":"They were the ones who failed to mutate and were simply discarded.","TWN":"這就是那些連變異都沒能完成，就被淘汰的人的下場。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그들이 노리는 건 단 한 가지일세.","JPN":"彼らが狙っているのはただ一つ。","ENG":"They only sought one thing.","TWN":"他們的目標只有一個。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그자들에겐 없었던, 완성에 가까운 자네의 인자지.","JPN":"自分たちにはなかった、完成品に近い君のファクターさ。","ENG":"Something they lacked. The perfected factor within you.","TWN":"就是那些人所沒有的，你那接近完美的因子。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 침식체들도 줄 서서 돈 내라 그래!","JPN":"じゃあ、侵食体も並んで金を払えっての！","ENG":"Then they better line up and pay for it!","TWN":"那就讓侵蝕體們也排隊交錢吧！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"머리통을 하나씩 박살 내줄 테니까!","JPN":"頭を1匹ずつぶち壊してやるから！","ENG":"I'll crush every single one of them, one by one!","TWN":"我要一個個地打爆你們的腦袋！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……!"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"불량식품!","JPN":"お菓子さん！","ENG":"Junk food!","TWN":"垃圾食物！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내가 연구를 시작한 이후 가장 먼저 시작한 것이 무엇인지 아나?","JPN":"私が研究を始めて、一番最初にしたことが何かわかるかね？","ENG":"Do you know what the very first step in my research was?","TWN":"你知道我在開始研究後最先做的是什麼嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"바로 자네 같은 감염자들의 약점을 알아내는 것이었네.","JPN":"君のような感染者たちの弱点を調べることだったよ。","ENG":"Figuring out the weaknesses of the afflicted like you.","TWN":"就是要找出像你這樣的感染者的弱點。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"은탄, 햇빛 등…… 유용한 방법들을 구비해뒀지.","JPN":"銀の弾、太陽の光……あらゆる有効な手段を用意している。","ENG":"Silver bullets, sunlight... I made sure to equip myself with all the necessary tools.","TWN":"銀彈、陽光等……我準備了很多有用的方法。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"언젠가 마주하게 될 이상 침식 현상을 일으킨 존재를 연구하기 위해서!","JPN":"いつか向き合うであろう、異常侵食現象を起こした存在を研究するために！","ENG":"To study the one who caused the Aberrant Counterside Effect, of course.","TWN":"為了研究某天會遇到的引發異常侵蝕現象的存在！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시 힘을 쓸 수 없었던 건 단순히 침식파 때문이 아니었어…….","JPN":"やっぱり力が使えなかったのは、侵食波のせいだけじゃなかったんだ……","ENG":"So that's why I couldn't use my full strength... It wasn't just the Corruption rays...","TWN":"果然無法使用力量不僅僅是因為侵蝕波……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 저 자식들을 힘겹게 상대했던 것도…….","JPN":"じゃあ、あいつらと戦うのに苦労したのも……","ENG":"That explains why I struggled against those things...","TWN":"那麼，之前和那些傢伙的辛苦對抗也是……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"수많은 실패작을 연구하면서 햇빛이 그들에게 어떻게 작용하는지 알아보았네.","JPN":"数多の失敗作を研究しながら、太陽の光が彼らにどう作用するか調べた。","ENG":"Through countless failed experiments, I learned how sunlight affects them.","TWN":"在研究了無數失敗品之後，我發現陽光是如何對他們起作用的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"햇빛이 활성화된 인자와 세포에 치명적인 작용을…….","JPN":"太陽光は、活性化したファクターと細胞に致命的な影響を……","ENG":"Sunlight is deadly to activated factors and mutated cells...","TWN":"陽光對活化的因子和細胞產生致命的作用……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 힘을 쓰지 못하도록 수작질했다는 거잖아.","JPN":"私が力をまともに出せないように小細工をしたってことじゃないか。","ENG":"So you set me up from the start to weaken me.","TWN":"現在就是說你耍了什麼手段讓我無法使用力量不是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그냥 닥쳐. 거슬리니까.","JPN":"もう黙れ。いい加減耳障りだ。","ENG":"Just shut up. You're getting on my nerves.","TWN":"閉嘴，你好吵。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네들에겐 승산이 없네.","JPN":"君たちに勝ち目はない。","ENG":"You have no chance of winning.","TWN":"你們是沒有勝算的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"창백한 달 감염자와 함께 연구에 협조하게나.","JPN":"青白い月の感染者と共に、私の研究に協力したまえ。","ENG":"You and the Pale Moon afflicted, accept your fate and cooperate with my research.","TWN":"請與蒼月感染者一起合作研究。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"고통스럽진 않을 걸세. 대부분은 의식을 잃은 채 실험에 참여할 테니.","JPN":"苦しくはないはずだ。ほとんどは意識を失った状態で実験に参加することになる。","ENG":"It won't be painful. You'll be unconscious for most of the experiments.","TWN":"不會痛苦的。大多數人都會在失去意識的情況下參與實驗。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나는 직업 윤리를 썩 잘 지키는 편이거든.","JPN":"私は研究倫理をきっちり守るほうでね。","ENG":"I pride myself on my professional ethics, after all.","TWN":"我可是很遵守職業操守的喔。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"헛소리 마시죠.","JPN":"ふざけないでください。","ENG":"Spare me your nonsense.","TWN":"少胡說八道。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};